					"    vec2 px = vec2(1.0 / resolution.x, 1.0 / resolution.y);",
					"    float totalAlpha = 0.0;",
					"    vec2 direction;",
					"    vec2 displaced;",
					"    vec4 color;",
					"    for (float angle = 0.0; angle < PI * 2.0; angle += SIZE)",
					"    {",
